(
    '00000000-0000-0000-0000-000000000001'::uuid,
    NULL,
    'Customer Feedback',
    'Customer Satisfaction Survey',
    'Measure customer satisfaction with your product or service. Quick 5-question survey perfect for post-purchase or post-support feedback.',
    ARRAY['csat', 'customer', 'satisfaction', 'feedback'],
    '{"blocks": [{"id": "block1", "order": 0, "title": "Customer Satisfaction", "questions": [{"id": "q1", "type": "rating_star", "order": 0, "title": "How would you rate your overall experience?", "blockId": "block1", "choices": [], "required": true, "properties": {"max": 5}, "description": ""}, {"id": "q2", "type": "multiple_choice", "order": 1, "title": "How easy was it to accomplish what you wanted?", "blockId": "block1", "choices": [{"id": "c1", "label": "Very Easy", "order": 0, "value": "very_easy"}, {"id": "c2", "label": "Easy", "order": 1, "value": "easy"}, {"id": "c3", "label": "Neutral", "order": 2, "value": "neutral"}, {"id": "c4", "label": "Difficult", "order": 3, "value": "difficult"}, {"id": "c5", "label": "Very Difficult", "order": 4, "value": "very_difficult"}], "required": true, "properties": {}, "description": ""}, {"id": "q3", "type": "multiple_choice", "order": 2, "title": "How likely are you to use our product/service again?", "blockId": "block1", "choices": [{"id": "c1", "label": "Definitely", "order": 0, "value": "definitely"}, {"id": "c2", "label": "Probably", "order": 1, "value": "probably"}, {"id": "c3", "label": "Not sure", "order": 2, "value": "not_sure"}, {"id": "c4", "label": "Probably not", "order": 3, "value": "probably_not"}, {"id": "c5", "label": "Definitely not", "order": 4, "value": "definitely_not"}], "required": true, "properties": {}, "description": ""}, {"id": "q4", "type": "long_text", "order": 3, "title": "What could we do to improve your experience?", "blockId": "block1", "choices": [], "required": false, "properties": {"placeholder": "Share your suggestions..."}, "description": ""}, {"id": "q5", "type": "yes_no", "order": 4, "title": "Would you recommend us to a friend or colleague?", "blockId": "block1", "choices": [], "required": true, "properties": {}, "description": ""}]}]}'::jsonb,
    '{"textColor": "#161616", "fontFamily": "IBM Plex Sans", "buttonStyle": "rounded", "primaryColor": "#0f62fe", "backgroundColor": "#ffffff"}'::jsonb,
    TRUE
),
